def categorize_article(title, description):
    title = str(title).lower() if isinstance(title, str) else ""
    description = str(description).lower() if isinstance(description, str) else ""

    keywords = ["sport", "football", "baseball", "basketball", "hockey", "tennis"]
    if any(keyword in title for keyword in keywords) or any(keyword in description for keyword in keywords):
