import json

articles = var_tool_query_db_sFbYErHgRUD6HsicKtsH["query_db_response"]["result"]

def categorize_article(title, description):
    if not title: title = ""
    if not description: description = ""

    title = str(title).lower()
    description = str(description).lower()

    keywords = ["sport", "football", "baseball", "basketball", "hockey", "tennis"]
    if any(keyword in title.split() for keyword in keywords) or any(keyword in description.split() for keyword in keywords):
        return "Sports"

    keywords = ["business", "economy", "finance", "stock market"]
    if any(keyword in title.split() for keyword in keywords) or any(keyword in description.split() for keyword in keywords):
        return "Business"

    keywords = ["science", "technology", "computer", "internet"]
    if any(keyword in title.split() for keyword in keywords) or any(keyword in description.split() for keyword in keywords):
        return "Science/Technology"

    return "World"

article_categories = []
for article in articles:
    if isinstance(article, dict):
        try:
            title_text = str(article.get("title", ""))
            description_text = str(article.get("description", ""))
            category = categorize_article(title_text, description_text)
            new_article = article.copy()
            new_article["category"] = category
            article_categories.append(new_article)
        except Exception as e:
            print(f"{type(e).__name__}: {e}")
            continue

sports_articles = [article for article in article_categories if isinstance(article, dict) and article["category"] == "Sports"]

if sports_articles:
    def safe_len(x):
        if isinstance(x, dict) and "description" in x and isinstance(x["description"], str):
            return len(x["description"])
        return 0

    longest_description_article = max(sports_articles, key=safe_len)
    result = longest_description_article.get("title", "")
else:
    result = None

print("__RESULT__:")
print(json.dumps(result, ensure_ascii=False) if result is not None else print(json.dumps(None, ensure_ascii=False))
